-- ----------------------------
-- Table structure for base_container_info
-- ----------------------------
DROP TABLE IF EXISTS `base_container_info`;
CREATE TABLE `base_container_info`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '序号',
  `container_uuid` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '集装箱uuid\r\n',
  `container_number` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '集装箱号',
  `container_type_id` int NOT NULL COMMENT '集装箱类型id base_container_type@id',
  `container_type_spec_id` int NULL DEFAULT NULL COMMENT '集装箱尺寸id base_container_type_spec@id',
  `container_attribute` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '集装箱属性 1 自有箱；2 长租箱； 3短租箱  字典吗：dict_container_attribute',
  `container_supplier_id` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '集装箱供应商 base_container_supplier@id',
  `city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '所在城市',
  `container_factory_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '集装箱所属堆场名称',
  `container_factory_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '集装箱所属堆场 base_container_factory@id',
  `temp_start` decimal(5, 2) NULL DEFAULT NULL COMMENT '温度起始 （下限）',
  `temp_end` decimal(5, 2) NULL DEFAULT NULL COMMENT '温度结束 （上限）',
  `fuel` decimal(6, 2) NULL DEFAULT NULL COMMENT '油量',
  `fuel_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '油料类型',
  `color` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '颜色',
  `batch` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '生产批次',
  `status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '集装箱使用状态： 0 可用 1在途 2锁定 3维修 4灭失。数据字典码： dict_container_status',
  `valid_start` bigint NULL DEFAULT NULL COMMENT '有效期开始10位时间戳',
  `valid_end` bigint NULL DEFAULT NULL COMMENT '有效期结束10位时间戳',
  `rental_cost` decimal(10, 2) NULL DEFAULT NULL COMMENT '租赁成本',
  `currency_id` int NULL DEFAULT NULL COMMENT 'base_currency@id',
  `exchange_rate` decimal(12, 2) NOT NULL DEFAULT 0.00 COMMENT '汇率',
  `container_life` int NULL DEFAULT NULL COMMENT '成色：1.新箱2.次新箱3.适货箱 数据字典码：dict_container_condition。',
  `production_time` bigint NULL DEFAULT NULL COMMENT '生产时间10位时间戳。',
  `manufacturer` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '生产厂家',
  `depreciation` decimal(12, 4) NULL DEFAULT NULL COMMENT '折旧',
  `purchase_price` decimal(12, 4) NULL DEFAULT NULL COMMENT '采购价格',
  `life_cycle` int NULL DEFAULT NULL COMMENT '寿命周期',
  `create_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否逻辑删除，此功能无用。',
  `version` int NULL DEFAULT NULL COMMENT '版本',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '备注',
  `create_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_name` varchar(50) CHARACTER SET utf32 COLLATE utf32_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `start_time` bigint NULL DEFAULT NULL COMMENT '开始堆存时间10位时间戳',
  `manual_status` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT '0' COMMENT '集装箱出场状态 0:系统出场 1:系统出场',
  `free_day` int NULL DEFAULT 0 COMMENT '免费堆存时长',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `uk_container_number`(`container_number` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6334 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '基础配置--集装箱管理' ROW_FORMAT = DYNAMIC;

